mapper.select:
select 
from t_r_service_registry
where `type` = #{type}
  and host = #{host}
  and port = #{port}
limit 1

mapper.update:
update t_r_service_registry
set heartbeat = #{heartbeat}
where `type` = #{type}
  and host = #{host}
  and port = #{port}
  and status = 'ONLINE'

update t_r_service_registry
set heartbeat = #{heartbeat},
    status = 'ONLINE'
where `type` = #{type}
  and host = #{host}
  and port = #{port}

update t_r_service_registry
set status = 'OFFLINE'
where `type` = #{type}
  and host = #{host}
  and port = #{port}
  and status = 'ONLINE'
